findings.codeql_raw_query:
/**
 * @name Jackson ObjectMapper HTML-unsafe JSON serialization
 * @description Check if Jackson ObjectMapper disables HTML escaping, making JSON unsafe for HTML embedding
 * @kind problem
 * @problem.severity error
 * @id java/jackson-html-unsafe
 * @tags security
 *       external/cwe/cwe-079
 *       external/cwe/cwe-116
 */
import java

// Find places where ObjectMapper is configured with ESCAPE_NON_ASCII or where
// disable(SerializationFeature.ESCAPE_NON_ASCII) or disableDefaultTyping etc. is called
// or where the mapper doesn't have HTML escaping enabled
from MethodCall mc
where
  (
    // Looking for disable of HTML escaping
    mc.getMethod().hasName("disable") and
    mc.getMethod().getDeclaringType().hasQualifiedName("com.fasterxml.jackson.databind", "ObjectMapper")
  ) or (
    // Looking for ObjectWriter without HTML encoding
    mc.getMethod().hasName("writeValueAsString") and
    mc.getMethod().getDeclaringType().hasQualifiedName("com.fasterxml.jackson.databind", "ObjectMapper")
  ) or (
    // Check for configure calls
    mc.getMethod().hasName("configure") and
    mc.getMethod().getDeclaringType().hasQualifiedName("com.fasterxml.jackson.databind", "ObjectMapper")
  ) or (
    // Check for factory configuration disabling HTML escaping
    mc.getMethod().hasName("disable") and
    mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("com.fasterxml.jackson.core", "JsonFactory")
  )
select mc, "Jackson ObjectMapper configuration: " + mc.getMethod().getName() + "() at line " + mc.getLocation().getStartLine() + " in " + mc.getEnclosingCallable().getDeclaringType().getName()
